+        .unwrap();
+
+        assert!(result.files.contains(&"config_summary.toml".to_string()));
+        let config_content =
+            fs::read_to_string(result.path.join("config_summary.toml")).unwrap();
+        assert!(config_content.contains("buffer_size"));
+    }
